CREATE TRIGGER [hubspot].trgUpdateservices
ON [hubspot].[services]
AFTER UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    UPDATE
        [hubspot].[services]
    SET
        __mj_UpdatedAt = GETUTCDATE()
    FROM
        [hubspot].[services] AS _organicTable
    INNER JOIN
        INSERTED AS I ON
        _organicTable.[hs_object_id] = I.[hs_object_id];
END;
